import React from 'react';

function TradeForm() {
    return(
        <form>
            <select autoFocus>
                <option>MES</option>
            </select>
            <select>
                <option>Bollinger</option>
                <option>--S & R--</option>
            </select>
            <input type='integer' min='1' step='1' />
        </form>  
    )
}

export default TradeForm;
